/**
 * MedX announcer accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Polite and assertive announcement queue.
 */
const ANNOUNCER_TOKENS = Object.freeze({
  primary: { value: "a11y-announcer-primary", scope: "a11y" },
  secondary: { value: "a11y-announcer-secondary", scope: "a11y" },
  muted: { value: "a11y-announcer-muted", scope: "a11y" },
  accent: { value: "a11y-announcer-accent", scope: "a11y" },
  surface: { value: "a11y-announcer-surface", scope: "a11y" },
});

const ANNOUNCER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ANNOUNCER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const announcerRegistry = new Map();
const ANNOUNCER_listeners = new Set();
let ANNOUNCER_seq = 0;

function createAnnouncerId(prefix = "medx-a11y-announcer") {
  ANNOUNCER_seq += 1;
  return `${prefix}-${ANNOUNCER_seq}`;
}

function registerAnnouncer(config = {}) {
  const entryId = config.id ?? createAnnouncerId();
  const preset = ANNOUNCER_PRESETS[config.preset ?? "default"] ?? ANNOUNCER_PRESETS.default;
  const token = ANNOUNCER_TOKENS[config.token ?? preset.token] ?? ANNOUNCER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ANNOUNCER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  announcerRegistry.set(entryId, entry);
  notifyAnnouncerListeners("register", entry);
  return entry;
}

function updateAnnouncer(id, patch = {}) {
  const entry = announcerRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyAnnouncerListeners("update", entry);
  return entry;
}

function resolveAnnouncer(id) {
  const entry = announcerRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listAnnouncerEntries(filter = {}) {
  let items = Array.from(announcerRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onAnnouncerEvent(listener) {
  ANNOUNCER_listeners.add(listener);
  return () => ANNOUNCER_listeners.delete(listener);
}

function notifyAnnouncerListeners(type, entry) {
  for (const listener of ANNOUNCER_listeners) {
    try {
      listener({ type, entry, registrySize: announcerRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:announcer] listener error", err.message);
    }
  }
}

function getAnnouncerMetrics() {
  const items = listAnnouncerEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ANNOUNCER_TOKENS).length,
    presets: Object.keys(ANNOUNCER_PRESETS).length,
  };
}

async function runMedxAnnouncer() {
  console.log("[medx:ui:a11y:announcer] runtime initialized");
  console.log(`[medx:ui:a11y:announcer] tokens=${Object.keys(ANNOUNCER_TOKENS).length} presets=${Object.keys(ANNOUNCER_PRESETS).length}`);

  const events = [];
  onAnnouncerEvent((e) => events.push(e.type));

  const domains = Object.keys(ANNOUNCER_SUPPLY_CHAIN);
  const presets = Object.keys(ANNOUNCER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerAnnouncer({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/announcer" },
    });
  }

  const first = listAnnouncerEntries()[0];
  if (first) updateAnnouncer(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getAnnouncerMetrics();
  const resolved = first ? resolveAnnouncer(first.id) : null;

  console.log(`[medx:ui:a11y:announcer] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:announcer] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:announcer] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:announcer] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:announcer] bootstrap complete");
}

module.exports = runMedxAnnouncer;
